import type { ReactNode } from "react";

import { cn } from "@/lib/utils";

import { Badge } from "@/components/ui/8bit/badge";
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
} from "@/components/ui/8bit/card";

import "@/components/ui/8bit/styles/retro.css";

export interface TimelineEvent {
  badge?: string;
  description: string;
  icon: ReactNode;
  title: string;
}

interface Timeline3Props {
  className?: string;
  description?: string;
  events?: TimelineEvent[];
  title?: string;
}

const defaultEvents: TimelineEvent[] = [
  {
    icon: "Q1",
    title: "Public Launch",
    description:
      "50+ components available. Registry goes live. Community Discord opens.",
    badge: "DONE",
  },
  {
    icon: "Q2",
    title: "Block System",
    description:
      "Full-page blocks: hero, pricing, FAQ, social proof. Build landing pages in minutes.",
    badge: "NOW",
  },
  {
    icon: "Q3",
    title: "Pro Templates",
    description:
      "Complete landing page templates. One-click deploy. Premium themes.",
  },
  {
    icon: "Q4",
    title: "Animation Pack",
    description:
      "Pixel transitions, sprite animations, and retro loading screens.",
  },
  {
    icon: "Q5",
    title: "Game UI Kit",
    description:
      "Inventory systems, dialogue boxes, battle UIs. Full game interface toolkit.",
  },
];

function EventCard({ event, align = "left" }: { event: TimelineEvent; align?: "left" | "right" }) {
  return (
    <Card>
      <CardHeader className="pb-2">
        <div className={cn("flex flex-col-reverse md:flex-row items-center gap-4", align === "right" && "justify-end")}>
          {align === "right" && event.badge && (
            <Badge className="text-[9px]">{event.badge}</Badge>
          )}
          <CardTitle className={cn("retro text-xs", align === "right" && "text-right")}>{event.title}</CardTitle>
          {align !== "right" && event.badge && (
            <Badge className="text-[9px]">{event.badge}</Badge>
          )}
        </div>
      </CardHeader>
      <CardContent>
        <p className={cn("text-muted-foreground text-[10px] leading-relaxed", align === "right" && "text-right")}>
          {event.description}
        </p>
      </CardContent>
    </Card>
  );
}

export default function Timeline3({
  title = "Roadmap",
  description = "Where we've been and where we're going",
  events = defaultEvents,
  className,
}: Timeline3Props) {
  return (
    <section className={cn("w-full px-4 py-16", className)}>
      <div className="mx-auto max-w-3xl">
        {(title || description) && (
          <div className="mb-10 text-center">
            {title && (
              <h2 className="retro mb-3 font-bold text-2xl tracking-tight md:text-3xl">
                {title}
              </h2>
            )}
            {description && (
              <p className="retro text-muted-foreground text-[9px]">{description}</p>
            )}
          </div>
        )}

        {/* Mobile: simple vertical (icon left + card right) */}
        <div className="flex flex-col gap-6 md:hidden">
          <div className="relative">
            <div className="absolute top-0 bottom-0 left-6 w-0 border-l-2 border-dashed border-border" />
            {events.map((event) => (
              <div className="relative flex gap-4 pb-6" key={event.title}>
                <div className="retro relative z-10 flex size-12 shrink-0 items-center justify-center border-2 border-primary bg-background font-bold text-sm">
                  {event.icon}
                </div>
                <div className="flex-1 pt-1">
                  <EventCard event={event} />
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Desktop: zigzag (alternating left/right) */}
        <div className="relative hidden md:block">
          <div className="absolute top-0 bottom-0 left-1/2 w-0 -translate-x-1/2 border-l-2 border-dashed border-border" />

          <div className="flex flex-col gap-8">
            {events.map((event, idx) => {
              const isLeft = idx % 2 === 0;

              return (
                <div
                  className="relative flex items-center"
                  key={event.title}
                >
                  {/* Left side */}
                  <div className="flex-1 pr-8">
                    {isLeft && (
                      <div>
                        <EventCard align="right" event={event} />
                      </div>
                    )}
                  </div>

                  {/* Center icon */}
                  <div className="retro relative z-10 flex size-12 shrink-0 items-center justify-center border-2 border-primary bg-background font-bold text-sm">
                    {event.icon}
                  </div>

                  {/* Right side */}
                  <div className="flex-1 pl-8">
                    {!isLeft && <EventCard event={event} />}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </section>
  );
}

@import url("https://fonts.googleapis.com/css2?family=Press+Start+2P&display=swap");

.retro {
  font-family:
    "Press Start 2P",
    system-ui,
    -apple-system,
    sans-serif;
  line-height: 1.5;
  letter-spacing: 0.5px;
}

.pixelated {
  image-rendering: pixelated;
  image-rendering: crisp-edges;
}

import { type VariantProps, cva } from "class-variance-authority";

import { cn } from "@/lib/utils";

import { Badge as ShadcnBadge } from "@/components/ui/badge";

export const badgeVariants = cva("", {
  variants: {
    font: {
      normal: "",
      retro: "retro",
    },
    variant: {
      default: "border-primary bg-primary",
      destructive: "border-destructive bg-destructive",
      outline: "border-background bg-background",
      secondary: "border-secondary bg-secondary",
    },
  },
  defaultVariants: {
    variant: "default",
  },
});

export interface BitButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof badgeVariants> {
  asChild?: boolean;
}

function Badge({
  children,
  className = "",
  font,
  variant,
  ...props
}: BitButtonProps) {
  const color = badgeVariants({ variant, font });

  const classes = className.split(" ");

  // visual classes for badge and sidebars
  const visualClasses = classes.filter(
    (c) =>
      c.startsWith("bg-") ||
      c.startsWith("border-") ||
      c.startsWith("text-") ||
      c.startsWith("rounded-")
  );

  // Container should accept all non-visual utility classes (e.g., size, spacing, layout)
  const containerClasses = classes.filter(
    (c) =>
      !(
        c.startsWith("bg-") ||
        c.startsWith("border-") ||
        c.startsWith("text-") ||
        c.startsWith("rounded-")
      )
  );

  return (
    <div className={cn("relative inline-flex items-stretch", containerClasses)}>
      <ShadcnBadge
        {...props}
        className={cn(
          "h-full",
          "rounded-none",
          "w-full",
          font !== "normal" && "retro",
          visualClasses
        )}
        variant={variant}
      >
        {children}
      </ShadcnBadge>

      {/* Left pixel bar */}
      <div
        className={cn(
          "-left-1.5 absolute inset-y-[4px] w-1.5",
          color,
          visualClasses
        )}
      />
      {/* Right pixel bar */}
      <div
        className={cn(
          "-right-1.5 absolute inset-y-[4px] w-1.5",
          color,
          visualClasses
        )}
      />
    </div>
  );
}

export { Badge };

import { type VariantProps, cva } from "class-variance-authority";

import { cn } from "@/lib/utils";

import {
  Card as ShadcnCard,
  CardAction as ShadcnCardAction,
  CardContent as ShadcnCardContent,
  CardDescription as ShadcnCardDescription,
  CardFooter as ShadcnCardFooter,
  CardHeader as ShadcnCardHeader,
  CardTitle as ShadcnCardTitle,
} from "@/components/ui/card";

import "@/components/ui/8bit/styles/retro.css";

export const cardVariants = cva("", {
  variants: {
    font: {
      normal: "",
      retro: "retro",
    },
  },
  defaultVariants: {
    font: "retro",
  },
});

export interface BitCardProps
  extends React.ComponentProps<"div">,
    VariantProps<typeof cardVariants> {
  asChild?: boolean;
}

function Card({ className, font, ...props }: BitCardProps) {
  return (
    <div
      className={cn(
        "relative bg-card text-card-foreground border-y-6 border-foreground dark:border-ring p-0!",
        className
      )}
    >
      <ShadcnCard
        {...props}
        className={cn(
          "rounded-none border-0 w-full! h-full flex flex-col bg-card text-card-foreground shadow-none",
          font !== "normal" && "retro",
          className
        )}
      />

      <div
        className={cn("absolute inset-0 border-x-6 -mx-1.5 border-inherit pointer-events-none")}
        aria-hidden="true"
      />
    </div>
  );
}

function CardHeader({ ...props }: BitCardProps) {
  const { className, font } = props;

  return (
    <ShadcnCardHeader
      className={cn(font !== "normal" && "retro", className)}
      {...props}
    />
  );
}

function CardTitle({ ...props }: BitCardProps) {
  const { className, font } = props;

  return (
    <ShadcnCardTitle
      className={cn(font !== "normal" && "retro", className)}
      {...props}
    />
  );
}

function CardDescription({ ...props }: BitCardProps) {
  const { className, font } = props;

  return (
    <ShadcnCardDescription
      className={cn(font !== "normal" && "retro", className)}
      {...props}
    />
  );
}

function CardAction({ ...props }: BitCardProps) {
  const { className, font } = props;

  return (
    <ShadcnCardAction
      className={cn(font !== "normal" && "retro", className)}
      {...props}
    />
  );
}

function CardContent({ ...props }: BitCardProps) {
  const { className, font } = props;

  return (
    <ShadcnCardContent
      className={cn("flex-1", font !== "normal" && "retro", className)}
      {...props}
    />
  );
}

function CardFooter({ ...props }: BitCardProps) {
  const { className, font } = props;

  return (
    <ShadcnCardFooter
      data-slot="card-footer"
      className={cn(font !== "normal" && "retro", className)}
      {...props}
    />
  );
}

export {
  Card,
  CardHeader,
  CardFooter,
  CardTitle,
  CardAction,
  CardDescription,
  CardContent,
};
